-- Generated from data/source-registry.json.
-- Safe to rerun. Existing robots_checked_at is preserved.

on conflict (id) do update set
  name = excluded.name,
  url = excluded.url,
  category = excluded.category,
  check_mode = excluded.check_mode,
  watch_urls = excluded.watch_urls,
  discovery_keywords = excluded.discovery_keywords,
  cadence = excluded.cadence,
  robots_checked_at = coalesce(public.official_sources.robots_checked_at, excluded.robots_checked_at),
  terms_note = case
    when public.official_sources.robots_checked_at is not null then public.official_sources.terms_note
    else excluded.terms_note
  end,
  updated_at = now();

update public.official_sources
set
  check_mode = 'disabled',
  terms_note = coalesce(terms_note, '') || ' Disabled by source-registry sync because this id is no longer present in data/source-registry.json.',
  updated_at = now()
where id not in ('pokemon-card-tcg', 'pokemon-goods-center', 'bandai-spirits-products', 'bandai-hobby-gunpla', 'ichiban-kuji-official', 'bandai-spirits-prize', 'tamashii-nations-official', 'dragonball-official', 'hololive-official', 'figure-makers-preorder', 'gashapon-official', 'namco-arcade-campaigns', 'gigo-arcade-campaigns', 'restaurant-chain-collabs', 'convenience-retail-anime-shops', 'publishers-shueisha-jump', 'publishers-kodansha-shogakukan', 'anime-adaptation-events', 'square-enix-dragonquest-goods', 'taito-prize-official', 'sega-plaza-prize', 'sanrio-official-goods', 'frieren-official', 'initiald-official-events', 'capcom-store-cafe-amusement', 'local-tourism-pilgrimage');
